import{_ as a,k as e,x as o,al as d}from"./chunks/framework.86H0f4-O.js";const r="/assets/1.COZ5PKAA.png",s="/assets/2.CUyxiOY-.png",i="/assets/3.CTOfcedF.png",l="/assets/4.CoUJpN-H.png",h="/assets/5.BfZ1aeuZ.png",q=JSON.parse('{"title":"ZeroTermux 入坑指南","description":"","frontmatter":{},"headers":[],"relativePath":"termux/ZeroTermux.md","filePath":"termux/ZeroTermux.md","lastUpdated":1771954379000}'),p={name:"termux/ZeroTermux.md"};function c(n,t,u,b,m,x){return e(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="zerotermux-入坑指南" tabindex="-1">ZeroTermux 入坑指南 <a class="header-anchor" href="#zerotermux-入坑指南" aria-label="Permalink to &quot;ZeroTermux 入坑指南&quot;">​</a></h1><p>ZeroTermux 是基于 Termux 二次开发的 Android 终端应用程序和 Linux 环境。</p><p>相较于原版 Termux，ZeroTermux 集成了备份恢复、容器切换、文件管理器等实用功能，对新手非常友好。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>说明</p><p>下文中的 Termux 均指代 ZeroTermux</p></div><h2 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h2><h3 id="更换镜像源" tabindex="-1">更换镜像源 <a class="header-anchor" href="#更换镜像源" aria-label="Permalink to &quot;更换镜像源&quot;">​</a></h3><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th></tr></thead><tbody><tr><td>1</td><td>按音量上键</td></tr><tr><td>2</td><td>在 &quot;常用功能&quot; 下找到并点击 &quot;切换源&quot;</td></tr><tr><td>3</td><td>选择 &quot;清华源&quot; 或 &quot;北京源&quot;</td></tr><tr><td>4</td><td>遇到 <code>yes/no</code> 全选 <code>y</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>注意</p><p>该方法只适用于 Termux 会话中。</p><p>若处于 proot 容器内，请先输入 <code>exit</code> 退出容器。</p></div><h2 id="区分-proot-容器" tabindex="-1">区分 proot 容器 <a class="header-anchor" href="#区分-proot-容器" aria-label="Permalink to &quot;区分 proot 容器&quot;">​</a></h2><h3 id="方法一-查看提示符" tabindex="-1">方法一：查看提示符 <a class="header-anchor" href="#方法一-查看提示符" aria-label="Permalink to &quot;方法一：查看提示符&quot;">​</a></h3><table tabindex="0"><thead><tr><th>提示符</th><th>状态</th><th>说明</th></tr></thead><tbody><tr><td><code>#</code></td><td>容器内</td><td>当前处于 proot 容器</td></tr><tr><td><code>$</code></td><td>容器外</td><td>当前在 Termux 会话</td></tr></tbody></table><p><img src="'+r+'" alt="处于proot容器"></p><p><img src="'+s+'" alt="不处于proot容器"></p><h3 id="方法二-查看用户" tabindex="-1">方法二：查看用户 <a class="header-anchor" href="#方法二-查看用户" aria-label="Permalink to &quot;方法二：查看用户&quot;">​</a></h3><p>显示 <code>root</code> 用户表示处于 proot 容器内。</p><h2 id="进入-proot-容器" tabindex="-1">进入 proot 容器 <a class="header-anchor" href="#进入-proot-容器" aria-label="Permalink to &quot;进入 proot 容器&quot;">​</a></h2><h3 id="tmoe-安装的容器" tabindex="-1">tmoe 安装的容器 <a class="header-anchor" href="#tmoe-安装的容器" aria-label="Permalink to &quot;tmoe 安装的容器&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">tmoe</span></span></code></pre></div><p>打开 tmoe 菜单，根据提示启动。</p><h3 id="发行版本安装的容器" tabindex="-1">发行版本安装的容器 <a class="header-anchor" href="#发行版本安装的容器" aria-label="Permalink to &quot;发行版本安装的容器&quot;">​</a></h3><p>在初始目录下会生成启动脚本，通常以 <code>arm64.sh</code> 结尾。</p><p>查看启动脚本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">ls</span></span></code></pre></div><p><img src="'+i+'" alt="启动脚本"></p><p>启动容器：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#98C379;"> buster-arm64.sh</span></span></code></pre></div><p>或</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#61AFEF;">./buster-arm64.sh</span></span></code></pre></div><h2 id="备份容器" tabindex="-1">备份容器 <a class="header-anchor" href="#备份容器" aria-label="Permalink to &quot;备份容器&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>前提条件</p><p>必须在 Termux 会话中操作，若处于 proot 容器内，请先输入 <code>exit</code> 退出。</p></div><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th></tr></thead><tbody><tr><td>1</td><td>按音量上键</td></tr><tr><td>2</td><td>选择&quot;备份/恢复&quot;</td></tr><tr><td>3</td><td>在弹出对话框中选择 <code>tar.gz</code></td></tr><tr><td>4</td><td>等待备份完成</td></tr></tbody></table><p>备份文件将保存在 <code>/sdcard/xinhao/data</code> 目录，可以分享给其他用户。</p><h2 id="恢复容器" tabindex="-1">恢复容器 <a class="header-anchor" href="#恢复容器" aria-label="Permalink to &quot;恢复容器&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>前提条件</p><ul><li>必须在 Termux 会话中操作</li><li>恢复包必须位于 <code>/sdcard/xinhao/data</code> 目录</li></ul></div><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th></tr></thead><tbody><tr><td>1</td><td>按音量上键</td></tr><tr><td>2</td><td>选择&quot;备份/恢复&quot;</td></tr><tr><td>3</td><td>点击恢复项</td></tr><tr><td>4</td><td>选择恢复包</td></tr><tr><td>5</td><td>输入新的容器名称</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>建议</p><ul><li>容器命名要清晰明了</li><li>不用的容器及时删除，释放存储空间</li></ul></div><h2 id="文件管理器" tabindex="-1">文件管理器 <a class="header-anchor" href="#文件管理器" aria-label="Permalink to &quot;文件管理器&quot;">​</a></h2><p>ZeroTermux 集成了强大的文件管理器，可以直接修改容器内的文件。</p><h3 id="安装文件管理器" tabindex="-1">安装文件管理器 <a class="header-anchor" href="#安装文件管理器" aria-label="Permalink to &quot;安装文件管理器&quot;">​</a></h3><table tabindex="0"><thead><tr><th>步骤</th><th>操作</th></tr></thead><tbody><tr><td>1</td><td>按音量上键呼出菜单栏</td></tr><tr><td>2</td><td>拉到下面，找到&quot;打开目录&quot;</td></tr><tr><td>3</td><td>安装插件</td></tr></tbody></table><p><img src="'+l+'" alt="打开目录"></p><h3 id="访问容器文件" tabindex="-1">访问容器文件 <a class="header-anchor" href="#访问容器文件" aria-label="Permalink to &quot;访问容器文件&quot;">​</a></h3><p>打开插件后，在右侧菜单选择&quot;访问 Utermux 文件&quot;。</p><p><img src="'+h+'" alt="访问Utermux文件"></p>',44)])])}const g=a(p,[["render",c]]);export{q as __pageData,g as default};
